mapper.select:
select
from appointment a left join sys_user su on a.user_id = su.id left join counselor c on a.counselor_id = c.id left join sys_user cu on c.user_id = cu.id left join counselor_schedule cs on a.schedule_id = cs.id left join feedback f on a.id = f.appointment_id
and a.status = 3
and a.appointment_no like concat('%', #{appointmentNo}, '%')
and a.user_id = #{userId}
and a.counselor_id = #{counselorId}
and f.score = #{score}
and f.is_anonymous = #{isAnonymous}
and f.id is not null
and f.id is null
order by a.update_time desc, a.id desc

select count(*)
from feedback
where appointment_id = #{appointmentId}
